<script setup lang="ts">
import { computed,ref } from 'vue'; import { useAuthStore } from '@/stores/auth'
const auth=useAuthStore(); const fullName=ref(auth.profile?.full_name||''); const phone=ref(auth.profile?.phone||''); const city=ref(auth.profile?.city||'Manta'); const sector=ref(auth.profile?.sector||''); const contact=ref(auth.profile?.preferred_contact||'correo'); const largeText=ref(Boolean(auth.profile?.accessibility_preferences?.large_text)); const highContrast=ref(Boolean(auth.profile?.accessibility_preferences?.high_contrast)); const saved=ref(false); const saving=ref(false); const initial=computed(()=>auth.userName.charAt(0).toUpperCase())
async function save(){saving.value=true;saved.value=await auth.updateProfile({full_name:fullName.value,phone:phone.value,city:city.value,sector:sector.value,preferred_contact:contact.value,accessibility_preferences:{large_text:largeText.value,high_contrast:highContrast.value}});saving.value=false}
</script>
<template><div class="page"><header><h1>Mi perfil</h1><p>Configura datos de contacto y preferencias de accesibilidad.</p></header><form class="card" @submit.prevent="save"><div class="avatar">{{initial}}</div><div class="grid"><div class="form-group"><label>Nombre completo</label><input v-model="fullName" class="form-input"/></div><div class="form-group"><label>Correo</label><input :value="auth.profile?.email" class="form-input" disabled/></div><div class="form-group"><label>Teléfono</label><input v-model="phone" class="form-input"/></div><div class="form-group"><label>Ciudad</label><input v-model="city" class="form-input"/></div><div class="form-group"><label>Sector</label><input v-model="sector" class="form-input"/></div><div class="form-group"><label>Contacto preferido</label><select v-model="contact" class="form-input"><option value="correo">Correo</option><option value="telefono">Teléfono</option></select></div></div><fieldset><legend>Accesibilidad</legend><label><input v-model="largeText" type="checkbox"/> Preferir texto grande</label><label><input v-model="highContrast" type="checkbox"/> Preferir alto contraste</label></fieldset><p v-if="saved" class="success">Perfil actualizado.</p><button class="btn btn-primary" :disabled="saving">{{saving?'Guardando...':'Guardar cambios'}}</button></form></div></template>
<style scoped>.page{padding:2rem;max-width:760px;margin:auto}.page header{margin-bottom:1rem}.page h1{color:var(--color-navy)}.page header p{color:var(--color-gray-500)}form{padding:1.4rem}.avatar{width:64px;height:64px;background:linear-gradient(135deg,#2dd4bf,#38bdf8);border-radius:50%;display:grid;place-items:center;font-size:1.8rem;font-weight:900;color:#083344;margin-bottom:1rem}.grid{display:grid;grid-template-columns:1fr 1fr;gap:.2rem 1rem}fieldset{border:1px solid var(--color-gray-200);border-radius:10px;padding:1rem;margin-bottom:1rem}fieldset legend{font-weight:800;color:var(--color-navy)}fieldset label{display:block;margin:.4rem 0;font-size:.85rem}.success{color:#166534;margin-bottom:.7rem}@media(max-width:600px){.page{padding:1rem}.grid{grid-template-columns:1fr}}</style>
